import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"鲁迅博物馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/lu-xun.md","filePath":"museums/lu-xun.md","lastUpdated":null}'),o={name:"museums/lu-xun.md"};function d(n,t,i,s,h,u){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="鲁迅博物馆" tabindex="-1">鲁迅博物馆 <a class="header-anchor" href="#鲁迅博物馆" aria-label="Permalink to &quot;鲁迅博物馆&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1545569341-9eb8b30979d9?w=1200" alt="鲁迅博物馆"></p><blockquote><p>&quot;横眉冷对千夫指，俯首甘为孺子牛。&quot; —— 鲁迅《自嘲》</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北京鲁迅博物馆位于西城区阜成门内西三条21号，是新中国最早建立的&quot;人物传记性博物馆&quot;。博物馆成立于1956年10月19日——鲁迅逝世20周年之际。</p><p>博物馆由鲁迅故居和鲁迅生平陈列馆两部分组成，完整展示了鲁迅在北京生活、工作的历史。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:00（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线阜成门站B口</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">微信公众号&quot;北京鲁迅博物馆&quot;</td></tr></tbody></table><h2 id="鲁迅与北京" tabindex="-1">鲁迅与北京 <a class="header-anchor" href="#鲁迅与北京" aria-label="Permalink to &quot;鲁迅与北京&quot;">​</a></h2><h3 id="在京岁月-1912-1926" tabindex="-1">在京岁月（1912-1926） <a class="header-anchor" href="#在京岁月-1912-1926" aria-label="Permalink to &quot;在京岁月（1912-1926）&quot;">​</a></h3><p>鲁迅在北京生活、工作了14年，这是他一生中最重要的创作时期之一。</p><table tabindex="0"><thead><tr><th style="text-align:left;">时期</th><th style="text-align:left;">经历</th></tr></thead><tbody><tr><td style="text-align:left;">1912年</td><td style="text-align:left;">随中华民国临时政府教育部迁往北京</td></tr><tr><td style="text-align:left;">1923年</td><td style="text-align:left;">购得阜成门内西三条21号房产</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">搬入新居，完成《野草》《彷徨》等作品</td></tr><tr><td style="text-align:left;">1926年</td><td style="text-align:left;">离开北京南下</td></tr></tbody></table><h3 id="故居岁月" tabindex="-1">故居岁月 <a class="header-anchor" href="#故居岁月" aria-label="Permalink to &quot;故居岁月&quot;">​</a></h3><p>1924年5月至1926年8月，鲁迅在这座小四合院中居住，完成了：</p><ul><li>小说集《彷徨》</li><li>散文诗集《野草》</li><li>杂文集《华盖集》《华盖集续编》</li></ul><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><p>鲁迅故居是一座典型的北京四合院，由鲁迅亲自设计改建。</p><h3 id="老虎尾巴" tabindex="-1">&quot;老虎尾巴&quot; <a class="header-anchor" href="#老虎尾巴" aria-label="Permalink to &quot;&quot;老虎尾巴&quot;&quot;">​</a></h3><p>故居最著名的建筑是北房后面接出的一间平顶灰棚，被鲁迅戏称为&quot;老虎尾巴&quot;。这是鲁迅的工作室兼卧室，《野草》大部分篇章在此完成。</p><h3 id="庭院" tabindex="-1">庭院 <a class="header-anchor" href="#庭院" aria-label="Permalink to &quot;庭院&quot;">​</a></h3><p>院内种植着鲁迅亲手栽种的树木：丁香、黄刺玫、榆叶梅等，至今依然茂盛。</p><h2 id="珍贵藏品" tabindex="-1">珍贵藏品 <a class="header-anchor" href="#珍贵藏品" aria-label="Permalink to &quot;珍贵藏品&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">藏品</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">鲁迅手稿</td><td style="text-align:left;">《野草》《彷徨》等原稿</td></tr><tr><td style="text-align:left;">藏书</td><td style="text-align:left;">约6000册</td></tr><tr><td style="text-align:left;">信件</td><td style="text-align:left;">与亲友往来的书信</td></tr><tr><td style="text-align:left;">生活用品</td><td style="text-align:left;">眼镜、钢笔、烟斗等</td></tr></tbody></table><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="从周树人到鲁迅" tabindex="-1">从周树人到鲁迅 <a class="header-anchor" href="#从周树人到鲁迅" aria-label="Permalink to &quot;从周树人到鲁迅&quot;">​</a></h3><p>鲁迅原名周树人，&quot;鲁迅&quot;这个笔名取自母亲鲁瑞的姓，寓意&quot;愚鲁而迅速&quot;。</p><h3 id="《新青年》与《狂人日记》" tabindex="-1">《新青年》与《狂人日记》 <a class="header-anchor" href="#《新青年》与《狂人日记》" aria-label="Permalink to &quot;《新青年》与《狂人日记》&quot;">​</a></h3><p>1918年，鲁迅以&quot;鲁迅&quot;为笔名发表了中国现代文学史上第一篇白话小说《狂人日记》，发出了&quot;救救孩子&quot;的时代呐喊。</p><h3 id="民族魂" tabindex="-1">&quot;民族魂&quot; <a class="header-anchor" href="#民族魂" aria-label="Permalink to &quot;&quot;民族魂&quot;&quot;">​</a></h3><p>鲁迅逝世后，覆盖在他棺木上的旗帜上写着&quot;民族魂&quot;三个大字，被誉为&quot;中国现代文学之父&quot;。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐参观顺序" tabindex="-1">推荐参观顺序 <a class="header-anchor" href="#推荐参观顺序" aria-label="Permalink to &quot;推荐参观顺序&quot;">​</a></h3><ol><li><strong>生平陈列馆</strong>（约1小时）</li><li><strong>故居小院</strong>（约30分钟）</li><li><strong>&quot;老虎尾巴&quot;</strong>（约15分钟）</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th></tr></thead><tbody><tr><td style="text-align:left;">妙应寺白塔</td><td style="text-align:center;">500米</td></tr><tr><td style="text-align:left;">广济寺</td><td style="text-align:center;">1公里</td></tr><tr><td style="text-align:left;">西四牌坊</td><td style="text-align:center;">1公里</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：鲁迅博物馆虽不大，但处处透着文化气息。建议在&quot;老虎尾巴&quot;多停留片刻，想象一下大师当年伏案写作的场景。</p>',37)])])}const f=e(o,[["render",d]]);export{x as __pageData,f as default};
